// Construimos el multipart manualmente con boundary
let boundary = "----NodeREDBoundary" + Date.now();

let CRLF = "\r\n";

// Parte 1: el archivo
let partArchivo =
    "--" + boundary + CRLF +
    "Content-Disposition: form-data; name=\"file\"; filename=\"" + msg.nombreSeguro + "\"" + CRLF +
    "Content-Type: image/jpeg" + CRLF +
    CRLF;

// Parte 2: el modelId
let partModelId =
    CRLF + "--" + boundary + CRLF +
    "Content-Disposition: form-data; name=\"modelId\"" + CRLF +
    CRLF +
    msg.modelId;

// Cierre
let cierre = CRLF + "--" + boundary + "--" + CRLF;

// Convertimos cada parte a Buffer y los concatenamos
let bufferInicio = Buffer.from(partArchivo, 'utf8');
let bufferImagen = msg.fotoSegura;
let bufferFin = Buffer.from(partModelId + cierre, 'utf8');

msg.payload = Buffer.concat([bufferInicio, bufferImagen, bufferFin]);

msg.headers = {
    "Content-Type": "multipart/form-data; boundary=" + boundary
};

msg.topic = "yolo";
return msg;

